record_types.code:
type Color_Type is record
  red, green, blue : Color_Value;
end record;

type Margins_Type is record
  left, right, top, bottom : Real;
end record;

type Point is record
  x, y : Real;
end record;

type Rectangle is record
  x_min, y_min,
  width, height : Real;
end record;

